+// ─── Pixel Art Character Rendering ─────────────────────────────────
+
+// Each character is 16x24 pixels with proper pixel art proportions:
+// Head: 6x6 px, torso: 8x10 px, legs: 8x8 px, arms: 4x10 px
+// Outlines, shading gradients, and distinctive features per type.
+
+type Palette = Record<string, string>;
+
+function drawPixel(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, color: string) {
+  ctx.fillStyle = color;
+  ctx.fillRect(x, y, s, s);
+}
+
+function drawOutline(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  ctx.strokeStyle = '#1a1018'; // Outline color (dark)
+  ctx.lineWidth = s * 0.15;
+  ctx.strokeRect(x, y, 16 * s, 24 * s);
+}
+
+function drawHead(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, palette: Palette, type: CharacterType) {
+  // Head base
+  for (let px = 5; px < 11; px++) {
+    for (let py = 0; py < 6; py++) {
+      let color = palette.S;
+      // Add shading on sides
+      if (px === 5 || px === 10) color = palette.s;
+      // Add hair top for some types
+      if (py < 2) {
+        if (type === 'king' || type === 'nobility' || type === 'judge') color = palette.H;
+        else if (type === 'blacksmith' || type === 'knight' || type === 'sentinel') color = palette.h;
+        else if (type === 'scribe' || type === 'healer' || type === 'squire') color = palette.h;
+      }
+      drawPixel(ctx, x + px * s, y + py * s, s, color);
+    }
+  }
+  // Eyes
+  drawPixel(ctx, x + 7 * s, y + 3 * s, s, palette.O);
+  drawPixel(ctx, x + 9 * s, y + 3 * s, s, palette.O);
+  // Mouth
+  drawPixel(ctx, x + 8 * s, y + 5 * s, s, palette.R);
+}
+
+function drawTorso(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, palette: Palette, type: CharacterType) {
+  // Torso base 8x10 px at (4,6)
+  for (let px = 4; px < 12; px++) {
+    for (let py = 6; py < 16; py++) {
+      let color = palette.P;
+      // Shade edges
+      if (px === 4 || px === 11) color = palette.p;
+      if (py === 6 || py === 15) color = palette.p;
+      // Add cape for king and nobility
+      if ((type === 'king' || type === 'nobility') && px >= 6 && px <= 9 && py >= 10) color = palette.K;
+      // Add apron for blacksmith
+      if (type === 'blacksmith' && py >= 10 && px >= 5 && px <= 10) color = palette.C;
+      drawPixel(ctx, x + px * s, y + py * s, s, color);
+    }
+  }
+  // Buttons or details
+  if (type === 'scribe' || type === 'judge') {
+    drawPixel(ctx, x + 7 * s, y + 10 * s, s, palette.W);
+    drawPixel(ctx, x + 8 * s, y + 12 * s, s, palette.W);
+    drawPixel(ctx, x + 9 * s, y + 14 * s, s, palette.W);
+  }
+}
+
+function drawArms(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, palette: Palette, type: CharacterType, flipH: boolean) {
+  // Arms 4x10 px at left (0,6) and right (12,6)
+  const leftX = flipH ? 12 : 0;
+  const rightX = flipH ? 0 : 12;
+  for (let px = 0; px < 4; px++) {
+    for (let py = 6; py < 16; py++) {
+      let colorL = palette.P;
+      let colorR = palette.P;
+      // Shade edges
+      if (px === 0) {
+        colorL = palette.p;
+        colorR = palette.p;
+      }
+      // Add gloves for knight, sentinel
+      if ((type === 'knight' || type === 'sentinel') && py >= 12) {
+        colorL = palette.B;
+        colorR = palette.B;
+      }
+      drawPixel(ctx, x + (leftX + px) * s, y + py * s, s, colorL);
+      drawPixel(ctx, x + (rightX + px) * s, y + py * s, s, colorR);
+    }
+  }
+}
+
+function drawLegs(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, palette: Palette, type: CharacterType, flipH: boolean) {
+  // Legs 8x8 px at (4,16)
+  for (let px = 4; px < 12; px++) {
+    for (let py = 16; py < 24; py++) {
+      let color = palette.P;
+      // Shade edges
+      if (px === 4 || px === 11) color = palette.p;
+      if (py === 23) color = palette.p;
+      // Boots for knight, sentinel, blacksmith
+      if ((type === 'knight' || type === 'sentinel' || type === 'blacksmith') && py >= 20) {
+        color = palette.B;
+      }
+      drawPixel(ctx, x + px * s, y + py * s, s, color);
+    }
+  }
+}
+
+function drawDistinctiveFeatures(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, palette: Palette, type: CharacterType) {
+  switch (type) {
+    case 'king':
+      // Crown (yellow/gold pixels on head top)
+      for (let px = 6; px < 10; px++) {
+        drawPixel(ctx, x + px * s, y + 0 * s, s, palette.G);
+      }
+      drawPixel(ctx, x + 5 * s, y + 1 * s, s, palette.G);
+      drawPixel(ctx, x + 10 * s, y + 1 * s, s, palette.G);
+      break;
+    case 'nobility':
+      // Fancy collar (crimson)
+      for (let px = 6; px < 10; px++) {
+        drawPixel(ctx, x + px * s, y + 15 * s, s, palette.R);
+      }
+      break;
+    case 'knight':
+      // Helmet top (dark gray)
+      for (let px = 5; px < 11; px++) {
+        drawPixel(ctx, x + px * s, y + 1 * s, s, palette.M);
+      }
+      // Visor line
+      for (let px = 6; px < 10; px++) {
+        drawPixel(ctx, x + px * s, y + 3 * s, s, palette.E);
+      }
+      break;
+    case 'squire':
+      // Simple tunic stripe (forest green)
+      for (let py = 10; py < 14; py++) {
+        drawPixel(ctx, x + 7 * s, y + py * s, s, palette.F);
+      }
+      break;
+    case 'healer':
+      // White cross on torso
+      drawPixel(ctx, x + 7 * s, y + 10 * s, s, palette.W);
+      drawPixel(ctx, x + 8 * s, y + 10 * s, s, palette.W);
+      drawPixel(ctx, x + 7 * s, y + 11 * s, s, palette.W);
+      drawPixel(ctx, x + 8 * s, y + 11 * s, s, palette.W);
+      break;
+    case 'sentinel':
+      // Shoulder pads (dark)
+      for (let px = 0; px < 4; px++) {
+        drawPixel(ctx, x + px * s, y + 6 * s, s, palette.M);
+        drawPixel(ctx, x + (12 + px) * s, y + 6 * s, s, palette.M);
+      }
+      break;
+    case 'scribe':
+      // Glasses (blue)
+      drawPixel(ctx, x + 6 * s, y + 3 * s, s, palette.L);
+      drawPixel(ctx, x + 9 * s, y + 3 * s, s, palette.L);
+      drawPixel(ctx, x + 7 * s, y + 3 * s, s, palette.W);
+      drawPixel(ctx, x + 8 * s, y + 3 * s, s, palette.W);
+      break;
+    case 'judge':
+      // Wig white curls top
+      for (let px = 5; px < 11; px++) {
+        drawPixel(ctx, x + px * s, y + 0 * s, s, palette.W);
+      }
+      break;
+    case 'blacksmith':
+      // Apron strap (brown)
+      for (let py = 6; py < 10; py++) {
+        drawPixel(ctx, x + 6 * s, y + py * s, s, palette.B);
+        drawPixel(ctx, x + 9 * s, y + py * s, s, palette.B);
+      }
+      break;
+  }
+}
+
+export function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  state: AnimState,
+  x: number, y: number, s: number, frame: number,
+  agentId?: string,
+  currentJob?: string | null,
+) {
+  const id = agentId ?? `${type}-${Math.round(x)}`;
+  const palette = PALETTE_MAP[type];
+  const cs = getCS(id, x, y);
+  const bob = state === 'idle' ? Math.sin(frame * 0.05) * 1.2 : state === 'working' ? Math.sin(frame * 0.1) * 0.8 : 0;
+  const drawY = cs.y + bob;
+  const flipH = cs.dir === 'left';
+
+  // Drop shadow ellipse under feet
+  ctx.fillStyle = 'rgba(0,0,0,0.3)';
+  ctx.beginPath();
+  ctx.ellipse(cs.x + 8 * s, drawY + 24 * s + 2, 7 * s, 2 * s, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  // Draw outline box for crispness
+  drawOutline(ctx, cs.x, drawY, s);
+
+  // Draw body parts
+  drawLegs(ctx, cs.x, drawY, s, palette, type, flipH);
+  drawTorso(ctx, cs.x, drawY, s, palette, type);
+  drawArms(ctx, cs.x, drawY, s, palette, type, flipH);
+  drawHead(ctx, cs.x, drawY, s, palette, type);
+  drawDistinctiveFeatures(ctx, cs.x, drawY, s, palette, type);
+
+  // Walking leg overlay (animated)
+  if (cs.moving) {
+    const lp = Math.sin(cs.wf * 0.3) * 2 * s;
+    ctx.fillStyle = palette.B;
+    // Left leg
+    ctx.fillRect(cs.x + 4 * s, drawY + 21 * s + lp, 3 * s, 3 * s);
+    // Right leg
+    ctx.fillRect(cs.x + 9 * s, drawY + 21 * s - lp, 3 * s, 3 * s);
+  }
+
+  drawStatusEffect(ctx, state, cs.x, drawY, s, frame);
+  if (agentId) {
+    updateBubble(id, state, currentJob ?? null, frame);
+    drawBubble(ctx, id, cs.x + 8 * s, drawY - 4);
+  }
+}
+
